<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Ubuntu Desktop</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  html, body { width: 100%; height: 100%; overflow: hidden; font-family: "Segoe UI", Ubuntu, Cantarell, "Helvetica Neue", Arial, sans-serif; }
  body { background: #2c001e; }

  #desktop {
    position: fixed; inset: 0;
    background:
      radial-gradient(ellipse at 30% 20%, rgba(119, 41, 83, 0.6), transparent 60%),
      radial-gradient(ellipse at 80% 80%, rgba(48, 10, 36, 0.8), transparent 60%),
      linear-gradient(135deg, #2c001e 0%, #4a0e3a 50%, #1a0014 100%);
