  }

  /* Top bar */
  #topbar {
    position: absolute; top: 0; left: 0; right: 0; height: 32px;
    background: rgba(20, 14, 20, 0.85);
    backdrop-filter: blur(10px);
    color: #fff;
    display: flex; align-items: center;
