  #topbar .clock { position: absolute; left: 50%; transform: translateX(-50%); font-weight: 600; }
  #topbar .sys { margin-left: auto; display: flex; gap: 14px; align-items: center; opacity: 0.9; }
  #topbar .sys span { cursor: default; }

  /* Dock / taskbar */
  #taskbar {
    position: absolute; bottom: 12px; left: 50%; transform: translateX(-50%);
    display: flex; gap: 10px;
    padding: 8px 12px;
    background: rgba(30, 20, 30, 0.75);
    backdrop-filter: blur(14px);
    border: 1px solid rgba(255,255,255,0.08);
    border-radius: 16px;
    z-index: 1000;
    box-shadow: 0 8px 30px rgba(0,0,0,0.5);
  }
  #taskbar button {
    width: 48px; height: 48px;
    border: none; border-radius: 12px;
    background: rgba(255,255,255,0.06);
    color: #fff;
    cursor: pointer;
    display: flex; align-items: center; justify-content: center;
    font-size: 22px;
    transition: background 0.15s, transform 0.15s;
    position: relative;
  }
  #taskbar button:hover { background: rgba(255,255,255,0.16); transform: translateY(-3px); }
  #taskbar button:active { transform: translateY(0); }
  #taskbar button .dot {
    position: absolute; bottom: -4px; left: 50%; transform: translateX(-50%);
    width: 6px; height: 6px; border-radius: 50%; background: #e95420;
