  #taskbar button.running .dot { opacity: 1; }

  /* Desktop icons */
  .desk-icon {
    position: absolute; color: #fff; width: 90px; text-align: center;
    padding: 8px 4px; border-radius: 8px; cursor: default; font-size: 12px;
  }
  .desk-icon:hover { background: rgba(255,255,255,0.1); }
  .desk-icon .glyph { font-size: 38px; line-height: 1; margin-bottom: 4px; }

  /* Windows */
  .window {
    position: absolute;
    min-width: 360px; min-height: 240px;
    background: #2b2b2b;
    color: #e8e8e8;
    border-radius: 10px;
    box-shadow: 0 18px 50px rgba(0,0,0,0.6), 0 2px 0 rgba(255,255,255,0.04) inset;
    display: flex; flex-direction: column;
    overflow: hidden;
    border: 1px solid rgba(0,0,0,0.5);
