  .win-btn {
    width: 14px; height: 14px; border-radius: 50%; border: none; cursor: pointer;
    display: flex; align-items: center; justify-content: center;
    font-size: 9px; color: rgba(0,0,0,0.55); font-weight: 700;
  }
  .win-close { background: #e95420; }
  .win-min { background: #f5b50a; }
  .win-max { background: #5ed16a; }
  .win-btn:hover { filter: brightness(1.15); }
  .win-body { flex: 1; overflow: auto; position: relative; }

  /* Files app */
  #files-window { width: 640px; height: 420px; left: 80px; top: 70px; }
  .files-toolbar {
    display: flex; align-items: center; gap: 8px;
    padding: 8px 10px; background: #383838; border-bottom: 1px solid #222;
  }
  .files-toolbar button {
    background: #4a4a4a; color: #eee; border: 1px solid #2a2a2a;
    border-radius: 6px; padding: 5px 12px; cursor: pointer; font-size: 13px;
  }
  .files-toolbar button:hover { background: #5a5a5a; }
  #files-path {
    flex: 1; background: #2b2b2b; color: #ddd; border: 1px solid #222;
    border-radius: 6px; padding: 5px 10px; font-size: 13px; font-family: monospace;
  }
  .files-list {
    display: grid; grid-template-columns: repeat(auto-fill, minmax(110px, 1fr));
    gap: 6px; padding: 14px;
  }
  .fs-item {
    display: flex; flex-direction: column; align-items: center;
    padding: 10px 6px; border-radius: 8px; cursor: pointer;
    text-align: center; font-size: 12px; color: #eee;
    transition: background 0.1s;
  }
  .fs-item:hover { background: rgba(255,255,255,0.08); }
  .fs-item.selected { background: rgba(233, 84, 32, 0.3); }
  .fs-item .icon { font-size: 40px; line-height: 1; margin-bottom: 6px; }
  .fs-item.folder .icon { color: #f5b50a; }
  .fs-item.file .icon { color: #c8c8c8; }

  /* Notepad app */
  #notepad-window { width: 560px; height: 400px; left: 360px; top: 110px; }
  .notepad-tabs {
    display: flex; align-items: flex-end; gap: 2px;
    background: #2a2a2a; padding: 6px 6px 0 6px;
    border-bottom: 1px solid #1a1a1a;
  }
  .tab {
    display: flex; align-items: center; gap: 8px;
    background: #383838; color: #ccc; padding: 7px 12px;
    border-radius: 8px 8px 0 0; cursor: pointer; font-size: 12px;
    border: 1px solid #2a2a2a; border-bottom: none;
    max-width: 160px;
  }
  .tab.active { background: #4a4a4a; color: #fff; }
  .tab .tab-name { white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
  .tab .tab-close {
    width: 16px; height: 16px; border-radius: 50%; background: rgba(255,255,255,0.1);
    display: flex; align-items: center; justify-content: center; font-size: 11px;
    border: none; cursor: pointer; color: #ccc;
  }
  .tab .tab-close:hover { background: #e95420; color: #fff; }
  #new-tab {
    background: #4a4a4a; color: #fff; border: 1px solid #2a2a2a;
    border-radius: 6px; padding: 5px 10px; cursor: pointer; font-size: 14px;
    align-self: center;
  }
  #new-tab:hover { background: #5a5a5a; }
  #editor {
    width: 100%; height: calc(100% - 38px);
    background: #1e1e1e; color: #e8e8e8; border: none; outline: none;
    padding: 14px; font-family: "Consolas", "Monaco", monospace; font-size: 14px;
    resize: none; line-height: 1.5;
  }

  /* Status hint */
  .hint {
    position: absolute; bottom: 78px; left: 50%; transform: translateX(-50%);
    color: rgba(255,255,255,0.4); font-size: 11px; pointer-events: none;
  }
</style>
</head>
<body>
<div id="desktop">
  <div id="topbar">
    <div class="activities">Activities</div>
    <div class="clock" id="clock">00:00</div>
    <div class="sys">
      <span>📶</span><span>🔊</span><span>🔋 100%</span>
    </div>
  </div>

  <div class="desk-icon" style="left:30px; top:60px;" ondblclick="document.getElementById('open-files').click()">
    <div class="glyph" style="color:#f5b50a">📁</div>Home
  </div>
  <div class="desk-icon" style="left:30px; top:160px;" ondblclick="document.getElementById('open-notepad').click()">
    <div class="glyph">📝</div>Notepad
  </div>

  <div id="taskbar">
    <button id="open-files" title="Files">📁<span class="dot"></span></button>
    <button id="open-notepad" title="Notepad">📝<span class="dot"></span></button>
  </div>

  <div class="hint">Double-click desktop icons or use the dock</div>

  <!-- Files Window -->
  <div id="files-window" class="window hidden">
    <div class="win-titlebar">
      <div class="win-controls">
        <button class="win-btn win-min" title="Minimize"></button>
        <button class="win-btn win-max" title="Maximize"></button>
        <button class="win-btn win-close" title="Close"></button>
      </div>
      <div class="win-title">Files</div>
    </div>
    <div class="win-body">
      <div class="files-toolbar">
        <button id="files-up" title="Parent directory">↑ Up</button>
        <div id="files-path">/</div>
      </div>
      <div class="files-list" id="files-list"></div>
    </div>
  </div>

  <!-- Notepad Window -->
  <div id="notepad-window" class="window hidden">
    <div class="win-titlebar">
      <div class="win-controls">
        <button class="win-btn win-min" title="Minimize"></button>
        <button class="win-btn win-max" title="Maximize"></button>
        <button class="win-btn win-close" title="Close"></button>
      </div>
      <div class="win-title">Notepad</div>
    </div>
    <div class="win-body" style="display:flex; flex-direction:column;">
      <div class="notepad-tabs" id="tabs"></div>
      <textarea id="editor" placeholder="Type something..."></textarea>
    </div>
  </div>
</div>

<script>
/* ---------- Filesystem (static fake data) ---------- */
const FS = {
  "/": {
    type: "dir",
    children: {
      bin:   { type: "dir", children: { bash: {type:"file"}, ls: {type:"file"}, cp: {type:"file"} } },
      etc:   { type: "dir", children: {
        "hostname": {type:"file"}, "hosts": {type:"file"}, "passwd": {type:"file"},
        "fstab": {type:"file"},
        nginx: { type:"dir", children: { "nginx.conf": {type:"file"} } }
      }},
      home:  { type: "dir", children: {
        user: { type: "dir", children: {
          Documents: { type:"dir", children: {
            "resume.txt": {type:"file"},
            "notes.md": {type:"file"},
            "project": { type:"dir", children: { "readme.md": {type:"file"} } }
          }},
          Downloads: { type:"dir", children: {
            "installer.deb": {type:"file"},
            "archive.tar.gz": {type:"file"}
          }},
          Pictures: { type:"dir", children: {
            "vacation.jpg": {type:"file"},
            "screenshot.png": {type:"file"},
            "wallpaper.png": {type:"file"}
          }},
          ".bashrc": {type:"file"},
          "todo.txt": {type:"file"}
        }}
      }},
      usr:   { type: "dir", children: {
        bin: { type:"dir", children: { python3: {type:"file"}, git: {type:"file"} } },
        lib: { type:"dir", children: { "libc.so": {type:"file"} } },
        share: { type:"dir", children: { "icons": {type:"dir", children:{}} } }
      }},
      var:   { type: "dir", children: {
        log: { type:"dir", children: { "syslog": {type:"file"}, "auth.log": {type:"file"} } },
        tmp: { type:"dir", children: {} },
        cache: { type:"dir", children: {} }
      }},
      tmp:   { type:"dir", children: {} },
      dev:   { type:"dir", children: { null: {type:"file"}, random: {type:"file"} } }
    }
  }
};

function fsResolve(path) {
  const parts = path === "/" ? [] : path.split("/").filter(Boolean);
  let node = FS["/"];
  for (const p of parts) {
    if (node.type !== "dir" || !node.children[p]) return null;
    node = node.children[p];
  }
  return node;
}

function fsParent(path) {
  if (path === "/") return "/";
  const parts = path.split("/").filter(Boolean);
  parts.pop();
  return parts.length ? "/" + parts.join("/") : "/";
}

function fsJoin(path, name) {
  return path === "/" ? "/" + name : path + "/" + name;
}

/* ---------- Files app ---------- */
let filesPath = "/";

function renderFiles() {
  const list = document.getElementById("files-list");
  const pathEl = document.getElementById("files-path");
  pathEl.textContent = filesPath;
  list.innerHTML = "";
  const node = fsResolve(filesPath);
  if (!node || node.type !== "dir") return;
  const names = Object.keys(node.children).sort();
  for (const name of names) {
    const child = node.children[name];
    const item = document.createElement("div");
    item.className = "fs-item " + (child.type === "dir" ? "folder" : "file");
    item.textContent = name;
    const icon = document.createElement("span");
    icon.className = "icon";
    icon.textContent = child.type === "dir" ? "📁" : "📄";
    item.insertBefore(icon, item.firstChild);
    item.addEventListener("dblclick", () => {
      if (child.type === "dir") {
        filesPath = fsJoin(filesPath, name);
        renderFiles();
      }
    });
    item.addEventListener("click", () => {
      list.querySelectorAll(".fs-item").forEach(el => el.classList.remove("selected"));
      item.classList.add("selected");
    });
    list.appendChild(item);
  }
}

document.getElementById("files-up").addEventListener("click", () => {
  if (filesPath !== "/") {
    filesPath = fsParent(filesPath);
    renderFiles();
  }
});

/* ---------- Notepad app (tabbed, persistent) ---------- */
const STORAGE_KEY = "ubuntu_notepad_tabs_v1";
let tabs = [];        // [{id, name, content}]
let activeTabId = null;

function loadTabs() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (raw) {
      const data = JSON.parse(raw);
      if (Array.isArray(data.tabs) && data.tabs.length) {
        tabs = data.tabs;
        activeTabId = data.activeTabId || tabs[0].id;
        return;
      }
    }
  } catch(e) {}
  // first run: create one default tab
  tabs = [{ id: "t" + Date.now(), name: "Untitled", content: "" }];
  activeTabId = tabs[0].id;
}

function saveTabs() {
  // sync current editor into active tab before saving
  const active = tabs.find(t => t.id === activeTabId);
  if (active) active.content = document.getElementById("editor").value;
  localStorage.setItem(STORAGE_KEY, JSON.stringify({ tabs, activeTabId }));
}

function renderTabs() {
  const strip = document.getElementById("tabs");
  strip.innerHTML = "";
  tabs.forEach(t => {
    const tab = document.createElement("div");
    tab.className = "tab" + (t.id === activeTabId ? " active" : "");
    tab.dataset.id = t.id;

    const name = document.createElement("span");
    name.className = "tab-name";
    name.textContent = t.name || "Untitled";
    tab.appendChild(name);

    const close = document.createElement("button");
    close.className = "tab-close";
    close.textContent = "×";
    close.title = "Close tab";
    close.addEventListener("click", (e) => {
      e.stopPropagation();
      closeTab(t.id);
    });
    tab.appendChild(close);

    tab.addEventListener("click", () => switchTab(t.id));
    strip.appendChild(tab);
  });

  const newBtn = document.createElement("button");
  newBtn.id = "new-tab";
  newBtn.textContent = "+";
  newBtn.title = "New tab";
  newBtn.addEventListener("click", newTab);
  strip.appendChild(newBtn);

  const active = tabs.find(t => t.id === activeTabId);
  document.getElementById("editor").value = active ? active.content : "";
}

function switchTab(id) {
  // save current editor content to currently active tab
  const cur = tabs.find(t => t.id === activeTabId);
  if (cur) cur.content = document.getElementById("editor").value;
  activeTabId = id;
  const active = tabs.find(t => t.id === id);
  document.getElementById("editor").value = active ? active.content : "";
  renderTabs();
  saveTabs();
}

function newTab() {
  const tab = { id: "t" + Date.now() + Math.random().toString(16).slice(2,6), name: "Untitled", content: "" };
  // save current editor content
  const cur = tabs.find(t => t.id === activeTabId);
  if (cur) cur.content = document.getElementById("editor").value;
  tabs.push(tab);
  activeTabId = tab.id;
  document.getElementById("editor").value = "";
  renderTabs();
  saveTabs();
  document.getElementById("editor").focus();
}

function closeTab(id) {
  const idx = tabs.findIndex(t => t.id === id);
  if (idx === -1) return;
  tabs.splice(idx, 1);
  if (tabs.length === 0) {
    tabs = [{ id: "t" + Date.now(), name: "Untitled", content: "" }];
    activeTabId = tabs[0].id;
  } else if (activeTabId === id) {
    activeTabId = tabs[Math.min(idx, tabs.length - 1)].id;
  }
  const active = tabs.find(t => t.id === activeTabId);
  document.getElementById("editor").value = active ? active.content : "";
  renderTabs();
  saveTabs();
}

document.getElementById("editor").addEventListener("input", () => {
  const active = tabs.find(t => t.id === activeTabId);
  if (active) {
    active.content = document.getElementById("editor").value;
    // auto-name tab from first line
    const firstLine = active.content.split("\n")[0].trim();
    active.name = firstLine ? firstLine.slice(0, 24) : "Untitled";
    // update tab name in DOM without full re-render to keep focus
    const tabEl = document.querySelector('.tab[data-id="' + active.id + '"] .tab-name');
    if (tabEl) tabEl.textContent = active.name;
    saveTabs();
  }
});

/* ---------- Window management ---------- */
function showWindow(win) {
  win.classList.remove("hidden");
  bringToFront(win);
  updateDockDots();
}
function hideWindow(win) {
  win.classList.add("hidden");
  updateDockDots();
}
function updateDockDots() {
  document.getElementById("open-files").classList.toggle("running", !document.getElementById("files-window").classList.contains("hidden"));
  document.getElementById("open-notepad").classList.toggle("running", !document.getElementById("notepad-window").classList.contains("hidden"));
}

let zCounter = 10;
function bringToFront(win) {
  zCounter += 1;
  win.style.zIndex = zCounter;
}

document.getElementById("open-files").addEventListener("click", () => {
  const w = document.getElementById("files-window");
  showWindow(w);
});
document.getElementById("open-notepad").addEventListener("click", () => {
  const w = document.getElementById("notepad-window");
  showWindow(w);
});

// Close buttons
document.querySelectorAll(".win-close").forEach(btn => {
  btn.addEventListener("click", (e) => {
    e.stopPropagation();
    const win = btn.closest(".window");
    hideWindow(win);
  });
});
// Minimize = hide
document.querySelectorAll(".win-min").forEach(btn => {
  btn.addEventListener("click", (e) => {
    e.stopPropagation();
    hideWindow(btn.closest(".window"));
  });
});
// Maximize toggle
document.querySelectorAll(".win-max").forEach(btn => {
  btn.addEventListener("click", (e) => {
    e.stopPropagation();
    const win = btn.closest(".window");
    if (win.dataset.maxd === "1") {
      win.dataset.maxd = "0";
      win.style.left = win.dataset.prevLeft;
      win.style.top = win.dataset.prevTop;
      win.style.width = win.dataset.prevW;
      win.style.height = win.dataset.prevH;
    } else {
      win.dataset.prevLeft = win.style.left;
      win.dataset.prevTop = win.style.top;
      win.dataset.prevW = win.style.width;
      win.dataset.prevH = win.style.height;
      win.dataset.maxd = "1";
      win.style.left = "0";
      win.style.top = "32px";
      win.style.width = "100%";
      win.style.height = "calc(100% - 32px)";
    }
  });
});

// Dragging
document.querySelectorAll(".win-titlebar").forEach(bar => {
  let dragging = false, ox = 0, oy = 0;
  bar.addEventListener("mousedown", (e) => {
    if (e.target.classList.contains("win-btn")) return;
    dragging = true;
    const win = bar.closest(".window");
    bringToFront(win);
    const rect = win.getBoundingClientRect();
    ox = e.clientX - rect.left;
    oy = e.clientY - rect.top;
    e.preventDefault();
  });
  document.addEventListener("mousemove", (e) => {
    if (!dragging) return;
    const win = bar.closest(".window");
    let x = e.clientX - ox;
    let y = e.clientY - oy;
    y = Math.max(32, y);
    x = Math.min(Math.max(-win.offsetWidth + 80, x), window.innerWidth - 80);
    win.style.left = x + "px";
    win.style.top = y + "px";
  });
  document.addEventListener("mouseup", () => { dragging = false; });
});

// Click window to focus
document.querySelectorAll(".window").forEach(win => {
  win.addEventListener("mousedown", () => bringToFront(win));
});

/* ---------- Clock ---------- */
function tickClock() {
  const d = new Date();
  const hh = String(d.getHours()).padStart(2, "0");
  const mm = String(d.getMinutes()).padStart(2, "0");
  document.getElementById("clock").textContent = hh + ":" + mm;
}
setInterval(tickClock, 1000);
tickClock();

/* ---------- Init ---------- */
loadTabs();
renderTabs();
renderFiles();
updateDockDots();

// Save tabs on unload
window.addEventListener("beforeunload", saveTabs);
</script>
</body>
</html>
